171	pub fn is_non_authored_path(path: &str) -> bool {
172	    // `git show --numstat` C-quotes any path with non-printable or non-ASCII
173	    // bytes, so the raw field can arrive wrapped in double quotes.
174	    let path = path.trim().trim_matches('"');
175	    let name = path.rsplit('/').next().unwrap_or(path);
176	    if LOCKFILE_NAMES.contains(&name) {
177	        return true;
178	    }
179	    name.rsplit_once('.').is_some_and(|(_, extension)| {
180	        CAPTURED_ARTIFACT_EXTENSIONS
181	            .iter()
182	            .any(|candidate| extension.eq_ignore_ascii_case(candidate))
183	    })
184	}
185	
186	fn changed_lines_for_commit(repo: &Path, commit: &str) -> Result<u64, String> {
187	    let output = git(
188	        repo,
189	        &["show", "--format=", "--numstat", "--no-renames", commit],
190	    )?;
191	    output.lines().try_fold(0_u64, |total, line| {
192	        let mut fields = line.split('\t');
193	        let additions = fields.next().unwrap_or_default();
194	        let deletions = fields.next().unwrap_or_default();
195	        let path = fields.next().unwrap_or_default();
196	        if additions == "-" || deletions == "-" {
197	            return Ok(total);
198	        }
199	        if is_non_authored_path(path) {
200	            return Ok(total);
201	        }
202	        let additions = additions
203	            .parse::<u64>()
204	            .map_err(|error| format!("invalid numstat additions in {commit}: {error}"))?;
205	        let deletions = deletions
206	            .parse::<u64>()
207	            .map_err(|error| format!("invalid numstat deletions in {commit}: {error}"))?;
208	        total
209	            .checked_add(additions)
210	            .and_then(|sum| sum.checked_add(deletions))
211	            .ok_or_else(|| format!("changed-line count overflowed in {commit}"))
212	    })
213	}
214	
215	fn commit_has_formal_ai_evidence(repo: &Path, commit: &str) -> Result<bool, String> {
216	    let sessions = trailer_values(repo, commit, SESSION_TRAILER)?;
217	    let evidence_paths = trailer_values(repo, commit, EVIDENCE_TRAILER)?;
218	    if sessions.is_empty() && evidence_paths.is_empty() {
219	        return Ok(false);
220	    }
221	    if sessions.is_empty() || evidence_paths.is_empty() {
222	        return Err(format!(
223	            "commit {commit} must record both {SESSION_TRAILER} and {EVIDENCE_TRAILER}"
224	        ));
225	    }
226	
227	    let mut evidence = Vec::with_capacity(evidence_paths.len());
228	    for path in evidence_paths {
229	        validate_evidence_path(&path)?;
230	        let object = format!("{commit}:{path}");
231	        let content = git(repo, &["show", &object])?;
232	        if !content.to_ascii_lowercase().contains("formal-ai") {
233	            return Err(format!(
234	                "evidence {path} in commit {commit} does not identify formal-ai"
235	            ));
236	        }
237	        evidence.push((path, content));
238	    }
239	
240	    for session in sessions {
241	        if !evidence
242	            .iter()
243	            .any(|(_, content)| content.contains(&session))
244	        {
245	            return Err(format!(
246	                "no committed {EVIDENCE_TRAILER} in {commit} records session {session}"
247	            ));
248	        }
249	    }
250	    Ok(true)
251	}
252	
253	/// Collects `key: value` trailers from a commit message.
254	///
255	/// This deliberately scans the whole commit body instead of using git's
